## 2. C++ Stubs (`pcapng_stubs.cpp`)

> **IMPORTANT** – this file must be compiled as C++ (e.g. `g++ -c -std=c++17 …`).
> The OCaml runtime is pure C, but the wrapper we write is C++ because the
> underlying library (`libpcapng`) is a C++ API.

```cpp
/* ----------------------------------------------------------------------
   pcapng_stubs.cpp – OCaml bindings for libpcapng
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE          /* avoid name clashes with C++ std:: */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>

#include <cstddef>
#include <cstdint>
#include <vector>
#include <string>
#include <stdexcept>
#include <memory>
#include <iostream>

/* ----------------------------------------------------------------------
   Minimal mock‑up of the libpcapng C++ API.
   In a real project you would #include <pcapng/reader.hpp> (or whatever)
   and use the actual classes.  For the purpose of a self‑contained example
   we provide a tiny stand‑in that reads a binary file and pretends each
   64‑byte chunk is a frame.
   ---------------------------------------------------------------------- */

namespace pcapng {

struct Frame {
    double   timestamp;          // seconds since epoch
    std::vector<std::uint8_t> data;
};

class Reader {
public:
    explicit Reader(const std::string& path) : file_(path, std::ios::binary) {
        if (!file_)
            throw std::runtime_error("cannot open file " + path);
    }

    ~Reader() = default;

    // Simple forward iterator – each call returns the next frame or nullptr.
    std::unique_ptr<Frame> next() {
        if (!file_) return nullptr;

        // For demo: each frame = 64 bytes of payload + 8‑byte timestamp.
        constexpr std::size_t CHUNK = 64;
        std::vector<std::uint8_t> buf(CHUNK);
        file_.read(reinterpret_cast<char*>(buf.data()), CHUNK);
        if (file_.gcount() == 0) return nullptr;   // EOF

        std::size_t got = static_cast<std::size_t>(file_.gcount());

        // Fake timestamp – just use the file offset as seconds.
        double ts = static_cast<double>(file_.tellg()) / 1e6;

        auto frame = std::make_unique<Frame>();
        frame->timestamp = ts;
        frame->data.assign(buf.begin(), buf.begin() + got);
        return frame;
    }

private:
    std::ifstream file_;
};

} // namespace pcapng

/* ----------------------------------------------------------------------
   OCaml custom block that stores a pointer to pcapng::Reader.
   ---------------------------------------------------------------------- */

struct caml_pcapng {
    pcapng::Reader *reader;
};

static void caml_pcapng_finalize(value v) {
    caml_pcapng *p = reinterpret_cast<caml_pcapng*>(Data_custom_val(v));
    delete p->reader;
    p->reader = nullptr;
}

static struct custom_operations caml_pcapng_ops = {
    "pcapng.reader",
    caml_pcapng_finalize,
    nullptr,                // compare
    nullptr,                // hash
    nullptr,                // serialize
    nullptr,                // deserialize
    nullptr,                // compare_ext
    nullptr                 // fixed_length
};

/* ----------------------------------------------------------------------
   Helper: allocate a fresh custom block wrapping a new Reader.
   ---------------------------------------------------------------------- */
static value caml_alloc_pcapng(pcapng::Reader *r) {
    CAMLparam0();
    CAMLlocal1(v);
    v = caml_alloc_custom(&caml_pcapng_ops, sizeof(caml_pcapng), 0, 1);
    caml_pcapng *p = reinterpret_cast<caml_pcapng*>(Data_custom_val(v));
    p->reader = r;
    CAMLreturn(v);
}

/* ----------------------------------------------------------------------
   OCaml entry points (exposed via CAMLprim)
   ---------------------------------------------------------------------- */

extern "C" {

/* open_file : string -> t */
CAMLprim value caml_pcapng_open_file(value path_v) {
    CAMLparam1(path_v);
    CAMLlocal1(res_v);
    const char *c_path = String_val(path_v);
    try {
        pcapng::Reader *r = new pcapng::Reader(std::string(c_path));
        res_v = caml_alloc_pcapng(r);
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    }
    CAMLreturn(res_v);
}

/* close : t -> unit */
CAMLprim value caml_pcapng_close(value handle_v) {
    CAMLparam1(handle_v);
    caml_pcapng *p = reinterpret_cast<caml_pcapng*>(Data_custom_val(handle_v));
    delete p->reader;
    p->reader = nullptr;
    CAMLreturn(Val_unit);
}

/* with_file : string -> (t -> 'a) -> 'a
   Implemented in OCaml (see the .mli file) – we expose it only for completeness. */
CAMLprim value caml_pcapng_with_file(value path_v, value f_v) {
    CAMLparam2(path_v, f_v);
    CAMLlocal1(handle_v);
    handle_v = caml_pcapng_open_file(path_v);
    value ret = caml_callback_exn(f_v, handle_v);
    /* Propagate any exception from the user function. */
    if (Is_exception_result(ret)) {
        caml_pcapng_close(handle_v);
        caml_raise(ret);
    }
    caml_pcapng_close(handle_v);
    CAMLreturn(ret);
}

/* --------------------------------------------------------------
   iter_frames : t -> (frame -> unit) -> unit
   -------------------------------------------------------------- */
CAMLprim value caml_pcapng_iter_frames(value handle_v, value cb_v) {
    CAMLparam2(handle_v, cb_v);
    caml_pcapng *p = reinterpret_cast<caml_pcapng*>(Data_custom_val(handle_v));
    if (!p->reader) caml_failwith("pcapng.handle is closed");

    while (true) {
        std::unique_ptr<pcapng::Frame> fr = p->reader->next();
        if (!fr) break;               // EOF

        /* ----------------------------------------------------------
           Build OCaml 'frame' record:
           type frame = { timestamp : float; data : bytes; length : int }
           ---------------------------------------------------------- */
        CAMLlocal3(frame_rec, data_bytes, timestamp_val);
        // data_bytes : bytes
        data_bytes = caml_alloc_string(fr->data.size());
        memcpy(String_val(data_bytes), fr->data.data(), fr->data.size());

        // timestamp : float
        timestamp_val = caml_copy_double(fr->timestamp);

        // frame_rec : record (3 fields)
        frame_rec = caml_alloc(3, 0);          // tag 0 = first constructor of record
        Store_field(frame_rec, 0, timestamp_val);
        Store_field(frame_rec, 1, data_bytes);
        Store_field(frame_rec, 2, Val_int(static_cast<int>(fr->data.size())));

        /* ----------------------------------------------------------
           Call the OCaml callback.  Use caml_callback_exn so we can
           detect a raise and abort the iteration cleanly.
           ---------------------------------------------------------- */
        value r = caml_callback_exn(cb_v, frame_rec);
        if (Is_exception_result(r)) {
            /* Propagate the exception outward – OCaml will see it as
               raised from iter_frames. */
            caml_raise(r);
        }
        /* No need to free anything; the GC will collect frame_rec and
           data_bytes after the callback returns. */
        CAMLdrop;   // release temporaries before next loop iteration
    }

    CAMLreturn(Val_unit);
}

} /* extern "C" */

/* ----------------------------------------------------------------------
   End of pcapng_stubs.cpp
   ---------------------------------------------------------------------- */
```

### What the stub does

1. **Open** – `caml_pcapng_open_file` creates a `pcapng::Reader` and wraps it in a
   custom OCaml block (`t`).  Errors are turned into `Failure` exceptions.
2. **Close** – `caml_pcapng_close` deletes the native object; the same
   finaliser runs automatically if the OCaml value is GC‑collected.
3. **Iterate** – `caml_pcapng_iter_frames` loops over native frames,
   constructs an OCaml `frame` record for each, and invokes the user‑supplied
   callback with `caml_callback_exn`.  If the callback raises, we unwind the
   iterator and re‑raise the exception.
4. **with_file** – a thin wrapper that opens a file, runs a user function on the
   handle, and guarantees `close` even when the function raises.

> **Thread‑safety note** – the stub does *not* release the OCaml runtime lock.
> The iterator runs in the same OS thread as the OCaml caller, which is fine
> for the typical single‑threaded use‑case.  If you ever need to run the
> iteration in a separate OS thread, you must call `caml_release_runtime_system`
> / `caml_acquire_runtime_system` around the callback, but that is beyond the
> scope of this minimal binding.

